class Solution:
    def validPalindrome(self, s: str) -> bool:
        origin = s
        plndrm = s[::-1]
        for i in range(len(origin)):
            if origin[i] == plndrm[i]:
                continue
            else:
                tempOrigin = s[:i] + s[i + 1:]
                tempPlndrm = tempOrigin[::-1]
                if tempOrigin == tempPlndrm:
                    return True

        if origin == plndrm:
            return True
        else:
            return False

